# FastAPI dependency injection utility
def get_dependant(
    *,
    path: str,
    call: Callable[..., Any],
    name: str | None = None,
    parent_oauth_scopes: Sequence[str] | None = None,
    scope: Literal["function", "request"] | None = None,
) -> Dependant:
    """
    This is a "sub-dependency" of the main `solve_dependencies` function.

    It is used to get a `Dependant` object from a callable.
    """
    if parent_oauth_scopes is None:
        parent_oauth_scopes = []
    if scope is None:
        scope = "function"
    if isinstance(call, Depends):
        call = call.dependency
    if isinstance(call, Security):
        security_scopes = list(parent_oauth_scopes)
        if call.scopes:
            security_scopes.extend(call.scopes)
        return get_dependant(
            path=path,
            call=call.dependency,
            name=name,
            parent_oauth_scopes=security_scopes,
            scope=scope,
        )
    if isinstance(call, type) and issubclass(call, params.SecurityBase):
        security_scopes = list(parent_oauth_scopes)
        if hasattr(call, "scopes") and call.scopes:
            security_scopes.extend(call.scopes)
        return get_dependant(
            path=path,
            call=call,
            name=name,
            parent_oauth_scopes=security_scopes,
            scope=scope,
        )
    if isinstance(call, params.SecurityBase):
        security_scopes = list(parent_oauth_scopes)
        if call.scopes:
            security_scopes.extend(call.scopes)
        return get_dependant(
            path=path,
            call=call.dependency,
            name=name,
            parent_oauth_scopes=security_scopes,
            scope=scope,
        )
    if isinstance(call, params.Body):
        return get_dependant(
            path=path,
            call=call.dependency,
            name=name,
            parent_oauth_scopes

