# FastAPI endpoint with a background task using standard parameter defaults and Python 3.10+ syntax.
from fastapi import BackgroundTasks, FastAPI, Query

app = FastAPI()

def write_log(message: str):
    with open("log.txt", "a") as log:
        log.write(message)

@app.get("/query")
async def get_query_endpoint(background_tasks: BackgroundTasks, q: str | None = Query(default=None)):
    if q:
        message = f"found query: {q}\n"
        background_tasks.add_task(write_log, message)
    return {"q": q}

